assignments.value:
={{ 
  parseFloat(
    $('Merge').item.json["CRÉDIO CONSIGNADO VALOR"]
      .split('$')
      .pop()                // ou .last(), dependendo da versão do n8n
      .replace('.', '')     // remove o ponto dos milhares
      .replace(',', '.')    // troca a vírgula por ponto decimal
  )
}}

={{ 
  (() => {
    const tel = $('Consulta credilus').first().json.data[0].TELEFONE.replace(/\D/g, '');
    return tel.length === 11 
      ? tel.replace(/^(\d{2})(\d{5})(\d{4})$/, '($1) $2-$3') 
      : tel.replace(/^(\d{2})(\d{4})(\d{4})$/, '($1) $2-$3');
  })()
}}

